/**
 * Renders the table based on the given arguments
 * @param {object} args - Arguments for the table
 * @param {Function} updateArgs - Function to update the story's arguments
 * @param {string} title - Title of the table
 * @param {boolean} [showTableActions=false] - Shows the example batch actions
 * @returns {import("lit").TemplateResult} Rendered table
 */
const tableRenderer = (args: any, updateArgs: any, title: string, showTableActions: Boolean) => {
  const {
    rows,
    count,
    selectedRows
  } = args;
  // let tableData = args.data || allData;

  const handlePageChange = (e: CustomEvent) => {
    updateArgs({
      pageSize: +e.detail.pageSize
    });
    updateArgs({
      pageNumber: +e.detail.pageNumber
    });
  };
  const handleSortByIdNumber = (e: CustomEvent) => {
    const {
      sortDirection
    } = e.detail;
    rows.sort(sortById(sortDirection));
    updateArgs({
      sorting: true
    });
  };
  const handleSortByAge = (e: CustomEvent) => {
    const {
      sortDirection
    } = e.detail;
    rows.sort(sortByAge(sortDirection));
    updateArgs({
      sorting: true
    });
  };
  const handleSortByFName = (e: CustomEvent) => {
    const {
      sortDirection
    } = e.detail;
    rows.sort(sortByFName(sortDirection));
    updateArgs({
      sorting: true
    });
  };
  const handleSortByLName = (e: CustomEvent) => {
    const {
      sortDirection
    } = e.detail;
    rows.sort(sortByLName(sortDirection));
    updateArgs({
      sorting: true
    });
  };
  const handleSortByDate = (e: CustomEvent) => {
    const {
      sortDirection
    } = e.detail;
    rows.sort(sortByDate(sortDirection));
    updateArgs({
      sorting: true
    });
  };
  const deleteAction = (id: number) => {
    const filteredRows = rows.filter((data: any) => data.id !== id);
    const filterSelectredRows = selectedRows.filter((data: any) => data !== id);
    const newCount = count ? filteredRows.length : 0;
    updateArgs({
      count: newCount,
      rows: filteredRows,
      selectedRows: filterSelectredRows
    });
  };
  const handleSelectedRowsChange = (e: CustomEvent) => {
    updateArgs({
      selectedRows: e.detail.selectedRows
    });
  };
  const deleteSelectedRows = () => {
    const filteredRows = rows.filter((row: any) => !selectedRows.includes(row.id));
    const newCount = count ? filteredRows.length : 0;
    updateArgs({
      count: newCount,
      rows: filteredRows,
      selectedRows: []
    });
  };
  const isPaginationEnabled = count > 0;
  const currentRows = isPaginationEnabled ? extractData(rows, args.pageNumber, args.pageSize) : rows;
  const columns: any[] = [{
    field: 'id',
    headerName: 'ID',
    sortable: true,
    align: 'center',
    sortFn: handleSortByIdNumber,
    maxWidth: '100px',
    elipsis: true
  }, {
    field: 'firstName',
    headerName: 'First name',
    align: 'left',
    sortable: true,
    sortFn: handleSortByFName,
    maxWidth: '200px',
    ellipsis: true
  }, {
    field: 'lastName',
    headerName: 'Last name',
    sortable: true,
    sortFn: handleSortByLName,
    maxWidth: '200px',
    ellipsis: true
  }, {
    field: 'birthday',
    headerName: 'Birthday',
    type: 'date',
    align: 'right',
    sortable: true,
    sortFn: handleSortByDate,
    maxWidth: '200px',
    ellipsis: true
  }, {
    field: 'age',
    headerName: 'Age',
    type: 'number',
    align: 'right',
    sortable: true,
    sortFn: handleSortByAge,
    maxWidth: '100px',
    ellipsis: true
  }, {
    field: 'fullName',
    headerName: 'Full name',
    description: 'This column has a value getter and is not sortable.',
    sortable: false,
    maxWidth: '300px',
    ellipsis: true,
    valueGetter: (params: any) => `${params.row.firstName || ''} ${params.row.lastName || ''}`
  }, {
    field: 'gender',
    headerName: 'Gender',
    align: 'center',
    maxWidth: '100px',
    valueGetter: (params: any) => {
      if (params.row.gender === 'male') {
        return html`<kd-icon .icon=${maleIcon}></kd-icon>`;
      } else {
        return html`<kd-icon .icon=${femaleIcon}></kd-icon>`;
      }
      return '';
    }
  }, {
    field: 'action',
    headerName: 'Action',
    align: 'center',
    openMenu: false,
    maxWidth: '100px',
    cellRenderer: ({
      row
    }: {
      row: any;
    }) => html`
          <action-menu
            .itemId=${row.id}
            .handleDelete=${deleteAction}
          ></action-menu>
        `
  }];
  const selectedCount = selectedRows?.length;
  const tableTitle = selectedCount > 0 ? selectedCount === 1 ? '1 item selected' : `${selectedCount} items selected` : title;
  return html`
    <div style=${args.stickyHeader ? 'height: 400px' : ''}>
      <kyn-table-toolbar tableTitle=${tableTitle}>
        ${showTableActions ? html` <batch-actions
              .handleDelete=${deleteSelectedRows}
            ></batch-actions>` : null}
      </kyn-table-toolbar>
      <kyn-data-table
        .fixedLayout=${args.fixedLayout}
        .columns=${columns}
        .rows=${currentRows}
        .selectedRows=${args.selectedRows}
        .checkboxSelection=${args.checkboxSelection}
        .stickyHeader=${args.stickyHeader}
        .dense=${args.dense}
        .striped=${args.striped}
        .paginationModel=${{
    ...args
  }}
        .hideItemsRange=${args.hideItemsRange}
        .hidePageSizeDropdown=${args.hidePageSizeDropdown}
        .hideNavigationButtons=${args.hideNavigationButtons}
        @on-page-changed=${handlePageChange}
        @on-selected-rows-changed=${handleSelectedRowsChange}
      ></kyn-data-table>
    </div>
  `;
};
